+            let candidate = &s[start..];
+            let Some(block) = extract_json_block(candidate) else {
+                break;
+            };
+            blocks.push(block);
+            let consumed = start + block.len();
+            if consumed >= s.len() {
+                break;
+            }
+            s = &s[consumed..];
+        }
+        blocks
+    }
