+fn required_step_command(
+    step: &PlanStep,
+    error_code: WizardErrorCode,
+) -> Result<&str, WizardError> {
+    step.command.as_deref().ok_or_else(|| {
+        WizardError::new(
+            error_code,
+            "Deployment plan step is missing its execution command",
+        )
+        .with_context(step.id.clone())
+    })
+}
